    B() { System.out.print("B"); }
    // exec method definition
    void exec() throws Exception {
        System.out.print("b");
        super.exec();
    }
}
// new B().exec() → Output: "ABba" + Exception thrown

// Shape class definition
class Shape {
    // area method definition
    double area() { return 0; }
    // toString method definition
    public String toString() { return "Shape:" + area(); }
}
//  yen class definition
class  yen extends Shape {
    double r;
     yen(double r) { this.r = r; }
    double area() { return 3.14 * r * r; }
}
// Main class definition
public class Main {
    public static void main(String[] args) {
        Shape s = new  yen(5);
        System.out.println(s);  // "Shape:78.5" (toString calls area(), and  yen's area is executed via dynamic binding)
    }
}

