public class Main {
    static String process() {
        String result = "";
        try {
            result += "T";
            int[] arr = new int[3];
            arr[5] = 10;
            result += "U";
        } catch (ArrayIndexOutOfBoundsException e) {
            result += "C";
        } finally {
            result += "F";
        }
        result += "E";
        return result;
    }
    public static void main(String[] args) {
        System.out.println(process());
    }
}
